SELECT pao.id, pao.user_id, pao.pet_id, pao.address_id, pao.detail, pao.status, pao.audit_error_detail, pao.is_again_post, pao.post_number, pao.create_time, u.username, u.avatar, p.name AS pet_name, p.cover, a.addressee, a.concat_phone, a.detail AS detail_address FROM pet_adopt_order pao LEFT JOIN user u ON u.id = pao.user_id LEFT JOIN pet p ON p.id = pao.pet_id LEFT JOIN address a ON a.id = pao.address_id
AND pao.user_id = #{userId}
AND pao.pet_id = #{petId}
AND pao.status = #{status}
AND pao.create_time BETWEEN #{startTime} AND #{endTime}
LIMIT #{current},#{size}

SELECT COUNT(*)
FROM pet_adopt_order pao


        AND pao.user_id = #{userId}


        AND pao.pet_id = #{petId}


        AND pao.status = #{status}


        AND pao.create_time BETWEEN #{startTime} AND #{endTime}
